What does this program print?

```cpp
#include <iostream>
#include <string>
struct Logger {
    int count{0};
    void log(const std::string& m) {
        ++count;
        std::cout << m << "\n";
    }
};
struct Worker {
    void run(Logger& lg) {
        lg.log("start");
        lg.log("end");
    }
};
int main() {
    Logger lg;
    Worker w;
    w.run(lg);
    std::cout << lg.count << "\n";
}
```

The intent is to log a message using a local Logger, but the program has a bug. What is it?

```cpp
#include <iostream>
#include <string>
struct Logger {
    void log(const std::string& msg) {
        std::cout << msg << "\n";
    }
};
struct Printer {
    Logger* lg;
    void print(const std::string& msg) {
        lg->log(msg);
    }
};
int main() {
    Printer p;
    Logger local;
    p.lg = &local;
    p.print("Hello");
}
```

What does this program print?

```cpp
#include <iostream>
struct Counter {
    int n{0};
    void increment() { ++n; }
};
void tick(Counter c) {   // passed by value
    c.increment();
    c.increment();
}
int main() {
    Counter c;
    tick(c);
    std::cout << c.n << "\n";
}
```
